def solve():
    left, right = input().split('|')
    unused = input()
    for i in range(len(unused)):
        if unused[i] in left:
            if unused[i] in right:
                continue
            right += unused[i]
            left = left.replace(unused[i], '')
        elif unused[i] in right:
            if unused[i] in left:
                continue
            left += unused[i]
            right = right.replace(unused[i], '')
        else:
            left += unused[i]
    if left == right:
        print(left + '|' + right)
    else:
        print('Impossible')


solve()
